"use client";

import { useEffect, useState } from "react";
import { useSearchParams, useRouter } from "next/navigation";
import Image from "next/image";
import Link from "next/link";
import { GoogleGenAI } from "@google/genai";

const CASE_LABELS: Record<string, Record<string, string>> = {
  ko: { civil: "민사소장", criminal: "형사고소장", copy: "복사", download: "다운로드", back: "다시 작성", print: "인쇄" },
  ru: { civil: "Гражданский иск", criminal: "Уголовная жалоба", copy: "Копировать", download: "Скачать", back: "Переписать", print: "Печать" },
  kz: { civil: "Азаматтық арыз", criminal: "Қылмыстық шағым", copy: "Көшіру", download: "Жүктеу", back: "Қайта жазу", print: "Басып шығару" },
  zh: { civil: "民事诉状", criminal: "刑事控告书", copy: "复制", download: "下载", back: "重新填写", print: "打印" },
  en: { civil: "Civil Complaint", criminal: "Criminal Complaint", copy: "Copy", download: "Download", back: "Rewrite", print: "Print" },
};

const LANG_NAMES: Record<string, string> = {
  ko: "한국어",
  ru: "Russian (Русский)",
  kz: "Kazakh (Қазақша)",
  zh: "Chinese (中文)",
  en: "English",
};

async function generateComplaint(params: Record<string, string>): Promise<string> {
  const { caseType, language, who, whom, when, where, what, how, why } = params;

  const ai = new GoogleGenAI({ apiKey: process.env.NEXT_PUBLIC_GEMINI_API_KEY });

  const caseTypeKor = caseType === "civil" ? "민사" : "형사";
  const inputLang = LANG_NAMES[language] || "한국어";

  // ── STEP 1: 다국어 입력 → 한국어 법률 구조 분석 ──
  const step1Prompt = `
당신은 한국 법률 전문가입니다.
아래 사건 정보는 ${inputLang}로 작성되었습니다. 내용을 완전히 이해하고 한국어 법률 용어로 구조화하세요.

사건 유형: ${caseTypeKor}
입력 언어: ${inputLang}

사건 정보:
- 누가 (원고/피해자): ${who}
- 누구에게 (피고/가해자): ${whom}
- 언제: ${when}
- 어디서: ${where}
- 무엇을: ${what}
- 어떻게: ${how}
- 왜: ${why}

위 내용을 분석하여 아래 JSON 형식으로만 응답하세요. 마크다운 없이 순수 JSON만 출력하세요:
{
  "원고": "원고/피해자 정보 (한국어)",
  "피고": "피고/가해자 정보 (한국어)",
  "청구유형": "${caseTypeKor} 사건의 청구 유형",
  "법적근거": "적용 가능한 한국 법률 및 조항",
  "청구취지": "원하는 구제 내용 또는 처벌 요청",
  "주요사실": ["사실1", "사실2", "사실3"],
  "증거방법": ["증거1", "증거2"],
  "번역요약": "사건 전체 내용을 한국어로 요약한 문장"
}`;

  const step1Response = await ai.models.generateContent({
    model: "gemini-1.5-flash",
    contents: "Explain how AI works in a few words",
  });
  const step1Text = (step1Response.text ?? "").replace(/```json|```/g, "").trim();

  let legalStructure = step1Text;
  try {
    JSON.parse(step1Text);
  } catch {
    legalStructure = step1Text;
  }

  // ── STEP 2: 법률 구조 → 한국어 소장 완성 ──
  const docTitle = caseType === "civil" ? "민사소장" : "형사고소장";

  const step2Prompt = `
당신은 한국 법원에 제출하는 공식 법률 문서 작성 전문가입니다.
아래 법률 구조 분석을 바탕으로 정식 ${docTitle}을 한국어로 작성하세요.

법률 구조 분석:
${legalStructure}

원본 사건 정보 (참고용):
- 원고/피해자: ${who}
- 피고/가해자: ${whom}
- 일시: ${when}
- 장소: ${where}
- 사건 내용: ${what}
- 경위: ${how}
- 동기/이유: ${why}

다음 형식에 맞춰 완전한 ${docTitle}을 한국어로만 작성하세요:

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
${docTitle}
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

${caseType === "civil"
  ? `원  고: [원고 성명 및 주소]
피  고: [피고 성명 및 주소]

【청구취지】
1. ...
2. ...
3. 소송비용은 피고가 부담한다.
라는 판결을 구합니다.

【청구원인】
1. 당사자의 지위
...
2. 사건의 경위
...
3. 피고의 불법행위
...
4. 손해배상 청구
...

【입증방법】
1. 갑 제1호증 ...
2. 갑 제2호증 ...

【첨부서류】
1. 위 입증방법 각 1통
2. 소장 부본 1통
3. 납부서 1통`
  : `고 소 인: [고소인 성명 및 주소]
피고소인: [피고소인 성명 및 주소]

【고소취지】
피고소인을 [해당 죄명]으로 고소하오니 엄중히 처벌하여 주시기 바랍니다.

【범죄사실】
1. 당사자 관계
...
2. 범행 경위
...
3. 범행 내용
...

【고소이유】
...

【입증방법】
1. 증 제1호증 ...
2. 증 제2호증 ...

【첨부서류】
1. 위 입증방법 각 1통
2. 고소장 부본 1통`}

                                    20  년    월    일

                        위 원고(고소인)                (인)

[관할 법원명] 귀중

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

위 형식에 맞춰 실제 내용을 채워 완성된 소장을 작성하세요.
반드시 한국어로만 작성하고, 법률 용어를 정확히 사용하세요.`;

  const step2Response = await ai.models.generateContent({
    model: "gemini-1.5-flash",
    contents: step2Prompt,
  });
  return step2Response.text ?? "소장 생성 중 오류가 발생했습니다.";
}

export default function ResultPage() {
  const searchParams = useSearchParams();
  const router = useRouter();
  const [result, setResult] = useState("");
  const [loading, setLoading] = useState(true);
  const [copied, setCopied] = useState(false);
  const [error, setError] = useState("");

  const params = Object.fromEntries(searchParams.entries());
  const language = params.language || "ko";
  const caseType = params.caseType || "civil";
  const L = CASE_LABELS[language] || CASE_LABELS.ko;
  const docTitle = caseType === "civil" ? L.civil : L.criminal;

  useEffect(() => {
    generateComplaint(params)
      .then(setResult)
      .catch((err) => {
        console.error(err);
        setError(err.message || "소장 생성 중 오류가 발생했습니다. 다시 시도해 주세요.");
      })
      .finally(() => setLoading(false));
  }, []);

  const handleCopy = () => {
    navigator.clipboard.writeText(result);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handlePrint = () => window.print();

  const handleDownload = () => {
    const blob = new Blob([result], { type: "text/plain;charset=utf-8" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `${docTitle}_${new Date().toISOString().slice(0, 10)}.txt`;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="min-h-screen bg-[#0a0f1e]">
      {/* Nav */}
      <nav className="fixed top-0 w-full z-50 bg-[#0a0f1e]/90 backdrop-blur-sm border-b border-white/10 print:hidden">
        <div className="max-w-7xl mx-auto px-6 h-16 flex items-center justify-between">
          <Link href="/" className="flex items-center gap-3">
            <Image
              src="https://ext.same-assets.com/549901695/2060650607.svg"
              alt="BALAW"
              width={80}
              height={28}
              className="h-7 w-auto"
            />
          </Link>
          <button
            type="button"
            onClick={() => router.push("/complaint/main_form")}
            className="text-sm text-white/50 hover:text-white transition-colors flex items-center gap-1.5"
          >
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
            </svg>
            {L.back}
          </button>
        </div>
      </nav>

      <div className="pt-24 pb-20 px-6 max-w-4xl mx-auto">
        {/* Header */}
        <div className="flex items-start justify-between mb-8 print:hidden">
          <div>
            <div className="flex items-center gap-2 mb-2">
              {loading ? (
                <span className="w-2 h-2 rounded-full bg-blue-400 animate-pulse inline-block" />
              ) : error ? (
                <span className="w-2 h-2 rounded-full bg-red-400 inline-block" />
              ) : (
                <span className="w-2 h-2 rounded-full bg-green-400 inline-block" />
              )}
              <p className={`text-xs font-semibold tracking-widest uppercase ${
                loading ? "text-blue-400" : error ? "text-red-400" : "text-green-400"
              }`}>
                {loading ? "Gemini AI 작성 중..." : error ? "오류 발생" : "AI 작성 완료"}
              </p>
            </div>
            <h1 className="text-2xl md:text-3xl font-bold text-white">{docTitle}</h1>
            {!loading && !error && (
              <p className="text-white/40 text-xs mt-1">
                입력 언어: {LANG_NAMES[language]} → 출력: 한국어 소장
              </p>
            )}
          </div>

          {!loading && !error && (
            <div className="flex items-center gap-2 flex-shrink-0">
              <button
                type="button"
                onClick={handleCopy}
                className="flex items-center gap-1.5 px-3 py-2 bg-white/8 border border-white/15 rounded-lg text-white/70 hover:text-white text-xs font-medium transition-all hover:border-white/30"
              >
                {copied ? (
                  <>
                    <svg className="w-3.5 h-3.5 text-green-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M5 13l4 4L19 7" />
                    </svg>
                    <span className="text-green-400">완료</span>
                  </>
                ) : (
                  <>
                    <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" />
                    </svg>
                    {L.copy}
                  </>
                )}
              </button>
              <button
                type="button"
                onClick={handleDownload}
                className="flex items-center gap-1.5 px-3 py-2 bg-white/8 border border-white/15 rounded-lg text-white/70 hover:text-white text-xs font-medium transition-all hover:border-white/30"
              >
                <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                </svg>
                {L.download}
              </button>
              <button
                type="button"
                onClick={handlePrint}
                className="flex items-center gap-1.5 px-3 py-2 bg-blue-600 border border-blue-500 rounded-lg text-white text-xs font-medium transition-all hover:bg-blue-500"
              >
                <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z" />
                </svg>
                {L.print}
              </button>
            </div>
          )}
        </div>

        {/* Document */}
        <div className="bg-white/5 border border-white/10 rounded-2xl overflow-hidden">
          {loading ? (
            <div className="flex flex-col items-center justify-center py-24 gap-5">
              <div className="relative">
                <div className="w-12 h-12 border-2 border-blue-500/30 rounded-full" />
                <div className="w-12 h-12 border-2 border-blue-500 border-t-transparent rounded-full animate-spin absolute inset-0" />
              </div>
              <div className="text-center space-y-1">
                <p className="text-white/70 text-sm font-medium">Gemini AI가 소장을 작성하고 있습니다</p>
                <p className="text-white/30 text-xs">Step 1: {LANG_NAMES[language]} 입력 분석 중...</p>
                <p className="text-white/30 text-xs">Step 2: 한국어 공식 소장 변환 중...</p>
              </div>
            </div>
          ) : error ? (
            <div className="flex flex-col items-center justify-center py-24 gap-4">
              <div className="w-12 h-12 rounded-full bg-red-500/20 border border-red-500/40 flex items-center justify-center text-red-400 text-xl font-bold">!</div>
              <p className="text-red-400 text-sm text-center max-w-sm leading-relaxed">{error}</p>
              <button
                type="button"
                onClick={() => router.push("/complaint/main_form")}
                className="px-4 py-2 bg-blue-600 text-white text-sm rounded-lg hover:bg-blue-500 transition-colors"
              >
                다시 시도하기
              </button>
            </div>
          ) : (
            <div className="p-8 md:p-12">
              <div className="bg-white rounded-xl p-8 md:p-12 shadow-2xl print:shadow-none">
                <pre className="whitespace-pre-wrap font-serif text-gray-800 text-sm md:text-base leading-relaxed">
                  {result}
                </pre>
              </div>
            </div>
          )}
        </div>

        {/* Disclaimer */}
        {!loading && !error && (
          <div className="mt-6 p-4 bg-amber-500/10 border border-amber-500/20 rounded-xl print:hidden">
            <p className="text-amber-400/80 text-xs leading-relaxed">
              ⚠️ 본 문서는 Google Gemini AI가 자동으로 생성한 초안입니다. 실제 법원 제출 전 반드시 변호사의 검토를 받으시기 바랍니다. BALAW의 전문 변호사가 최종 검토를 도와드릴 수 있습니다.
            </p>
          </div>
        )}
      </div>

      <style>{`
        @media print {
          body { background: white; }
          .print\\:hidden { display: none !important; }
        }
      `}</style>
    </div>
  );
}